  'admin_mission_2': { fr: 'Configuration des paramètres globaux du système', en: 'Configuration of global system settings', es: 'Configuración de los ajustes globales del sistema', zh: '全局系统设置配置', ja: 'グローバルシステム設定の構成' },
  'admin_mission_3': { fr: 'Supervision des présences et résolution des anomalies', en: 'Attendance supervision and anomaly resolution', es: 'Supervisión de asistencia y resolución de anomalías', zh: '考勤监督和异常解决', ja: '出席の監督と異常の解決' },
  'admin_mission_4': { fr: 'Génération et analyse des rapports statistiques', en: 'Generation and analysis of statistical reports', es: 'Generación y análisis de informes estadísticos', zh: '统计报表的生成和分析', ja: '統計レポートの作成と分析' },
  'admin_mission_5': { fr: 'Gestion de la sécurité et du réseau', en: 'Security and network management', es: 'Gestión de seguridad y red', zh: '安全和网络管理', ja: 'セキュリティとネットワークの管理' },
  'teacher_role_title': { fr: 'Enseignant', en: 'Teacher', es: 'Profesor', zh: '教师', ja: '教師' },
  'teacher_role_desc': { fr: 'En tant qu\'enseignant, vous êtes au cœur du dispositif pédagogique. Vous assurez le suivi de vos classes et la validation des présences.', en: 'As a teacher, you are at the heart of the educational process. You ensure the follow-up of your classes and the validation of attendance.', es: 'Como docente, estás en el centro del proceso educativo. Aseguras el seguimiento de tus clases y la validación de la asistencia.', zh: '作为一名教师，您处于教学过程的核心。您负责班级的后续跟进和考勤验证。', ja: '教師として、あなたは教育プロセスの中心にいます。クラスのフォローアップと出席の確認を行います。' },
  'teacher_mission_1': { fr: 'Gestion de l\'appel en classe et validation des présences', en: 'Classroom roll call management and attendance validation', es: 'Gestión de pasar lista en clase y validación de asistencia', zh: '课堂点名管理和考勤验证', ja: '教室での点呼管理と出席確認' },
  'teacher_mission_2': { fr: 'Suivi de l\'assiduité des élèves de vos cours', en: 'Monitoring the attendance of students in your courses', es: 'Seguimiento de la asistencia de los estudiantes en sus cursos', zh: '监控您课程中学生的出勤情况', ja: 'コースの生徒の出席状況のモニタリング' },
  'teacher_mission_3': { fr: 'Consultation des emplois du temps et des listes de classes', en: 'Consultation of schedules and class lists', es: 'Consulta de horarios y listas de clases', zh: '查阅时间表和班级名单', ja: 'スケジュールとクラスリストの参照' },
  'teacher_mission_4': { fr: 'Communication avec l\'administration concernant les absences', en: 'Communication with administration regarding absences', es: 'Comunicación con la administración sobre las ausencias', zh: '就缺勤事宜与管理部门沟通', ja: '欠席に関する管理者との連絡' },
  'student_role_title': { fr: 'Élève / Étudiant', en: 'Student', es: 'Alumno / Estudiante', zh: '学生', ja: '生徒 / 学生' },
  'student_role_desc': { fr: 'En tant qu\'élève, cette plateforme vous permet de suivre votre assiduité et de consulter vos ressources pédagogiques.', en: 'As a student, this platform allows you to track your attendance and consult your educational resources.', es: 'Como estudiante, esta plataforma te permite realizar un seguimiento de tu asistencia y consultar tus recursos educativos.', zh: '作为一名学生，该平台允许您跟踪自己的出勤情况并查阅您的教育资源。', ja: '生徒として、このプラットフォームでは出席状況を追跡し、教育リソースを参照できます。' },
  'student_mission_1': { fr: 'Consultation de votre historique de présence et statistiques', en: 'Consultation of your attendance history and statistics', es: 'Consulta de tu historial de asistencia y estadísticas', zh: '查阅您的出勤历史记录和统计数据', ja: '出席履歴と統計の参照' },
  'student_mission_2': { fr: 'Visualisation de votre emploi du temps et devoirs', en: 'Visualization of your schedule and homework', es: 'Visualización de tu horario y tareas', zh: '查看您的时间表和作业', ja: 'スケジュールと課題の表示' },
  'student_mission_3': { fr: 'Accès aux ressources de la bibliothèque numérique', en: 'Access to digital library resources', es: 'Acceso a los recursos de la biblioteca digital', zh: '访问数字图书馆资源', ja: 'デジタルライブラリリソースへのアクセス' },
  'student_mission_4': { fr: 'Suivi de vos notes et évaluations', en: 'Monitoring your grades and evaluations', es: 'Seguimiento de tus notas y evaluaciones', zh: '监控您的成绩和评估', ja: '成績と評価のモニタリング' },
  'admin_staff_role_title': { fr: 'Personnel Administratif', en: 'Administrative Staff', es: 'Personal administrativo', zh: '行政人员', ja: '行政スタッフ' },
  'admin_staff_role_desc': { fr: 'En tant que membre de l\'administration, vous assurez le suivi quotidien de la vie scolaire et la gestion des flux d\'élèves.', en: 'As a member of the administration, you ensure the daily follow-up of school life and the management of student flows.', es: 'Como miembro de la administración, aseguras el seguimiento diario de la vida escolar y la gestión de los flujos de alumnos.', zh: '作为管理部门的一员，您负责学校生活的日常跟进和学生流动的 management。', ja: '行政のメンバーとして、学校生活の日々のフォローアップと生徒の流れの管理を行います。' },
  'admin_staff_mission_1': { fr: 'Gestion des retards, absences et justifications', en: 'Management of lateness, absences and justifications', es: 'Gestión de retrasos, ausencias y justificaciones', zh: '迟到、缺勤和辩解的管理', ja: '遅刻、欠席、および正当な理由の管理' },
