  'how_to_use_prompts_desc': { fr: 'Copiez le prompt de votre choix et collez-le dans l\'onglet Préparations IA ou utilisez-le directement avec Gemini.', en: 'Copy the prompt of your choice and paste it into the AI Preparations tab or use it directly with Gemini.', es: 'Copie el prompt de su elección y péguelo en la pestaña Preparaciones de IA o úselo directamente con Gemini.', zh: '复制您选择的提示并将其粘贴到 AI 准备选项卡中，或直接与 Gemini 一起使用。', ja: '選択したプロンプトをコピーして [AI 準備] タブに貼り付けるか、Gemini で直接使用します。' },
  'ai_lesson_plan_desc_short': { fr: 'Génère un plan de cours complet avec objectifs, matériel et étapes.', en: 'Generate a full lesson plan with objectives, materials, and steps.', es: 'Genera un plan de lección completo con objetivos, materiales y pasos.', zh: '生成包含目标、材料和步骤的完整教案。', ja: '目標、教材、手順を含む完全な指導案を生成します。' },
  'ai_lesson_plan_prompt': { fr: 'Rédige un plan de cours détaillé pour une séance de 55 minutes sur [SUJET] pour des élèves de [NIVEAU]. Inclus : Objectifs pédagogiques, Matériel nécessaire, Introduction (5 min), Développement (40 min), et Conclusion/Évaluation (10 min).', en: 'Write a detailed lesson plan for a 55-minute session on [SUBJECT] for [LEVEL] students. Include: Pedagogical objectives, Necessary material, Introduction (5 min), Development (40 min), and Conclusion/Evaluation (10 min).', es: 'Escribe un plan de lección detallado para una sesión de 55 minutos sobre [TEMA] para estudiantes de [NIVEL]. Incluye: Objetivos pedagógicos, Material necesario, Introducción (5 min), Desarrollo (40 min) y Conclusión/Evaluación (10 min).', zh: '为 [级别] 学生编写关于 [主题] 的 55 分钟详细教案。包括：教学目标、必要材料、介绍（5 分钟）、发展（40 分钟）以及结论/评估（10 分钟）。', ja: '[LEVEL]の学生を対象とした[SUBJECT]に関する55分間の詳細な指導案を作成してください。内容：教育目標、必要な教材、導入（5分）、展開（40分）、結論/評価（10分）。' },
  'exercises_generator': { fr: 'Générateur d\'exercices', en: 'Exercises Generator', es: 'Generador de ejercicios', zh: '练习生成器', ja: '演習ジェネレーター' },
  'ai_exercises_desc_short': { fr: 'Crée une série d\'exercices progressifs avec corrigés.', en: 'Create a series of progressive exercises with keys.', es: 'Crea una serie de ejercicios progresivos con soluciones.', zh: '创建一系列带有答案的递进练习。', ja: '解答付きの一連の漸進的な演習を作成します。' },
  'ai_exercises_prompt': { fr: 'Génère 5 exercices progressifs sur [SUJET] pour le niveau [NIVEAU]. Les exercices doivent aller du plus simple au plus complexe. Fournis également les corrigés détaillés pour chaque exercice.', en: 'Generate 5 progressive exercises on [SUBJECT] for the [LEVEL] level. Exercises should go from simplest to most complex. Also provide detailed keys for each exercise.', es: 'Genera 5 ejercicios progresivos sobre [TEMA] para el nivel [NIVEL]. Los ejercicios deben ir de lo más simple a lo más complejo. También proporcione soluciones detalladas para cada ejercicio.', zh: '为 [级别] 级别生成关于 [主题] 的 5 个递进练习。练习应从最简单到最复杂。同时为每个练习提供详细答案。', ja: '[LEVEL]レベルの[SUBJECT]に関する5つの漸進的な演習を生成してください。演習は最も単純なものから最も複雑なものへと進む必要があります。また、各演習の詳細な解答も提供してください。' },
  'concept_simplification': { fr: 'Simplification de concept', en: 'Concept Simplification', es: 'Simplificación de conceptos', zh: '概念简化', ja: '概念の単純化' },
  'ai_concept_desc_short': { fr: 'Explique un concept complexe avec des mots simples.', en: 'Explain a complex concept with simple words.', es: 'Explica un concepto complejo con palabras simples.', zh: '用简单的词语解释复杂的概念。', ja: '複雑な概念を簡単な言葉で説明してください。' },
  'ai_concept_prompt': { fr: 'Explique le concept de [CONCEPT] à un enfant de 10 ans en utilisant des analogies simples et un langage accessible. Évite le jargon technique.', en: 'Explain the concept of [CONCEPT] to a 10-year-old child using simple analogies and accessible language. Avoid technical jargon.', es: 'Explique el concepto de [CONCEPTO] a un niño de 10 años usando analogías simples y lenguaje accesible. Evite la jerga técnica.', zh: '使用简单的类比和易懂的语言向 10 岁的孩子解释 [概念] 的概念。避免技术术语。', ja: '10歳の子どもに[CONCEPT]の概念を、簡単な例えとわかりやすい言葉を使って説明してください。専門用語は避けてください。' },
  'quiz_generator': { fr: 'Générateur de Quiz', en: 'Quiz Generator', es: 'Generador de cuestionarios', zh: '测验生成器', ja: 'クイズジェネレーター' },
  'ai_quiz_desc_short': { fr: 'Génère un QCM de 10 questions avec options et explications.', en: 'Generate a 10-question MCQ with options and explanations.', es: 'Genera un MCQ de 10 preguntas con opciones y explicaciones.', zh: '生成包含选项和解释的 10 道多选题。', ja: 'オプションと解説付きの10問の多肢選択式クイズを生成します。' },
  'ai_quiz_prompt': { fr: 'Crée un QCM de 10 questions sur [SUJET] pour le niveau [NIVEAU]. Pour chaque question, propose 4 options (A, B, C, D) et indique la bonne réponse avec une brève explication.', en: 'Create a 10-question MCQ on [SUBJECT] for the [LEVEL] level. For each question, offer 4 options (A, B, C, D) and indicate the correct answer with a brief explanation.', es: 'Crea un MCQ de 10 preguntas sobre [TEMA] para el nivel [NIVEL]. Para cada pregunta, ofrece 4 opciones (A, B, C, D) e indica la respuesta correcta con una breve explicación.', zh: '为 [级别] 级别创建关于 [主题] 的 10 道多选题。对于每个问题，提供 4 个选项（A、B、C、D），并指出正确答案并附上简短说明。', ja: '[LEVEL]レベルの[SUBJECT]に関する10問の多肢選択式クイズを作成してください。各質問に4つの選択肢（A、B、C、D）を用意し、正解と短い解説を添えてください。' },
  'type_interrogation': { fr: 'Interrogation', en: 'Quiz', es: 'Interrogatorio', zh: '提问', ja: '小テスト' },
