interface LanguageContextType {
  language: Language;
  setLanguage: (lang: Language) => void;
  t: (key: string) => string;
  tData: (value: string) => string;
}

const LanguageContext = createContext<LanguageContextType | undefined>(undefined);

export const LanguageProvider: React.FC<{ children: React.ReactNode }> = ({ children }) => {
  const [language, setLanguage] = useState<Language>(() => {
    const saved = localStorage.getItem('app_language');
    return (saved as Language) || 'fr';
  });

  useEffect(() => {
    localStorage.setItem('app_language', language);
  }, [language]);

  const t = (key: string) => {
    return translations[key]?.[language] || key;
  };

  const tData = (value: string) => {
    if (!value) return value;
    const keyMap: Record<string, string> = {
      'admin': 'role_admin',
      'enseignant': 'role_enseignant',
      'élève': 'role_élève',
      'parent': 'role_parent',
      'personnel administratif': 'role_personnel administratif',
      'cuisinier': 'role_cuisinier',
      'Présent': 'status_Présent',
      'Retard': 'status_Retard',
      'Absent': 'status_Absent',
      'Tous': 'all',
      'Lun': 'day_Lun',
      'Mar': 'day_Mar',
      'Mer': 'day_Mer',
      'Jeu': 'day_Jeu',
      'Ven': 'day_Ven',
      'interrogation': 'type_interrogation',
      'evaluation': 'type_evaluation',
    };
    const key = keyMap[value];
    return key ? t(key) : value;
  };

  return (
    <LanguageContext.Provider value={{ language, setLanguage, t, tData }}>
      {children}
    </LanguageContext.Provider>
  );
};

export const useLanguage = () => {
  const context = useContext(LanguageContext);
  if (!context) throw new Error('useLanguage must be used within LanguageProvider');
  return context;
};
